#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract text from PDF
sub extract_text_from_pdf {
    my ($pdf_file) = @_;

    my $pdf = PDF::API2->open($pdf_file);

    my $text = '';
    foreach my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->page($page);
        $text .= $page_obj->text();
    }

    return $text;
}

# Function to extract specific information from the text
sub extract_info {
    my ($text) = @_;
    my %info;

    # Extract author
    if ($text =~ /Author:\s+([^\n]+)/) {
        $info{author} = $1;
    }

    # Extract title
    if ($text =~ /Title:\s+([^\n]+)/) {
        $info{title} = $1;
    }

    # Extract date (assuming a date is in the format MM/DD/YYYY)
    if ($text =~ /Date:\s+([01]?[0-9]\/[0-3]?[0-9]\/[0-9]{4})/) {
        $info{date} = $1;
    }

    return %info;
}

